changeSet.sql:
CREATE TABLE gdpr_article_paragraph
(
	id serial,
	organization_id integer DEFAULT NULL,
	article_id integer DEFAULT NULL,
	paragraph_number character varying (8) DEFAULT NULL,
	name character varying (127) NOT NULL,
	description text DEFAULT NULL,
	CONSTRAINT pk_gdpr_article_paragraph PRIMARY KEY (id)
	, CONSTRAINT fk_gdpr_article_paragraph_to_organization FOREIGN KEY (organization_id) REFERENCES organizations (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE CASCADE
	, CONSTRAINT fk_gdpr_article_paragraph_to_chapter FOREIGN KEY (article_id) REFERENCES gdpr_article (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE CASCADE
);
CREATE INDEX i_gdpr_article_paragraph_organization_id ON gdpr_article_paragraph (organization_id);
CREATE INDEX i_gdpr_article_paragraph_article_id ON gdpr_article_paragraph (article_id);
CREATE INDEX i_gdpr_article_paragraph_name ON gdpr_article_paragraph (name);
